#include <bits/stdc++.h>
using namespace std;
int main(){
    int sum2=0,sum5=0,n;
    cin>>n;
    for(int i=1;i<=n;i++){
        int tmp=i;
        while(tmp%2==0)tmp/=2,sum2++;
        while(tmp%5==0)tmp/=5,sum5++;
    }
    int num2=min(sum2,sum5),num5=num2,ans=1;
    for(int i=2;i<=n;i++){
        int tmp=i;
        while(tmp%2==0 && num2)tmp/=2,num2--;
        while(tmp%5==0 && num5)tmp/=5,num5--;
        ans*=tmp%10;
        ans%=10;
    }
    cout<<ans;
    return 0;
}
